import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { auth } from "@/lib/auth";
import { FolderKanban, Plus } from "lucide-react";
import { headers } from "next/headers";
import Link from "next/link";
import { redirect } from "next/navigation";

export default async function ProjectsPage() {
  const result = await auth.api.getSession({
    headers: await headers(),
  });

  if (!result?.session?.userId) {
    redirect("/sign-in");
  }

  return (
    <section className="flex w-full flex-col items-start justify-start p-6">
      <div className="mb-8 flex w-full flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Projects</h1>
          <p className="text-muted-foreground mt-1 max-w-xl">
            Mock backends you define with schemas, generated data, and live
            REST endpoints—one project per workspace.
          </p>
        </div>
        <Button type="button" disabled className="shrink-0 gap-2">
          <Plus className="size-4" aria-hidden />
          New project
        </Button>
      </div>

      <Card className="border-depth w-full max-w-2xl border-dashed">
        <CardHeader className="text-center sm:text-left">
          <div className="bg-primary/10 text-primary mx-auto mb-2 flex size-12 items-center justify-center rounded-lg sm:mx-0">
            <FolderKanban className="size-6" aria-hidden />
          </div>
          <CardTitle>No projects yet</CardTitle>
          <CardDescription>
            When you create a project, it will show up here with its tables,
            mock data, and runtime API base URL.
          </CardDescription>
        </CardHeader>
        <CardContent className="flex justify-center pb-8 sm:justify-start">
          <Button variant="outline" asChild>
            <Link href="/dashboard">Back to overview</Link>
          </Button>
        </CardContent>
      </Card>
    </section>
  );
}
